module decoder_2_to_4 (
    input wire [1:0] in,
    output reg [3:0] out
);
  wire [1:0] _tap_in = in & {2{1'b1}};


always @(*) begin
    case (in)
        2'b00: out = 4'b0001;
        2'b01: out = 4'b0010;
        2'b10: out = 4'b0100;
        2'b11: out = 4'b1000;
        default: out = 4'b0000; // Should never happen
    endcase
end

endmodule
